name:
if (Test-Path "D:\ruangtato\components.json") { Get-Content "D:\ruangtato\components.json" -Raw } else { "NO components.json" }
Write-Output "---deps---"
$pkg = Get-Content "D:\ruangtato\package.json" -Raw | ConvertFrom-Json
@("next","react","tailwindcss","framer-motion","motion","tw-animate-css","clsx","tailwind-merge","class-variance-authority","lucide-react") | ForEach-Object {
  $v = $pkg.dependencies.$_; if (-not $v) { $v = $pkg.devDependencies.$_ }
  "{0}: {1}" -f $_, ($(if($v){$v}else{"-"}))
}

